+    fn csv_escape_text_sanitizes_newlines_and_quotes() {
+        let input = "Hello\r\n\"world\", ok";
+        let escaped = csv_escape_text(input);
+        assert_eq!(escaped, "Hello  \"\"world\"\", ok");
+    }
+}

